import os,sys,yaml,json
from glob import glob
p='docs-site/docs'
pages=[]
for f in glob(p+'/*.md'):
    with open(f,'r',encoding='utf-8') as fh:
        txt=fh.read()
    fm=None
    if txt.startswith('---'):
        parts=txt.split('---',2)
        if len(parts)>2:
            try:
                fm=yaml.safe_load(parts[1])
            except Exception as e:
                fm={}
    title=None
    if fm and 'title' in fm:
        title=fm['title']
    else:
        # try to get first heading
        for line in txt.splitlines():
            if line.strip().startswith('# '):
                title=line.strip()[2:]
                break
    pages.append({
        'path': os.path.basename(f),
        'title': title,
        'audience': fm.get('audience') if fm else None,
        'tags': fm.get('tags') if fm else [],
        'summary': fm.get('summary') if fm else None
    })
print(json.dumps({'generated_at':None,'pages':pages},indent=2))
